sql_query:
SELECT "Follow-up duration for primary endpoint(s) in months | Overall"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Follow-up duration for primary endpoint(s) in months | Overall" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_followup_maturity(source_value) AS "maturity"
FROM base;
